import React, { useState } from "react";
import { ArrowRight, X } from "lucide-react";

// 1. IMPORT ALL 30 IMAGES EXPLICITLY
// React requires this so it can bundle them properly for production
import pic1 from "../../images/pic1.jpeg";
import pic2 from "../../images/pic2.jpeg";
import pic3 from "../../images/pic3.jpeg";
import pic4 from "../../images/pic4.jpeg";
import pic5 from "../../images/pic5.jpeg";
import pic6 from "../../images/pic6.jpeg";
import pic7 from "../../images/pic7.jpeg";
import pic8 from "../../images/pic8.jpeg";
import pic9 from "../../images/pic9.jpeg";
import pic10 from "../../images/pic10.jpeg";
import pic11 from "../../images/pic11.jpeg";
import pic12 from "../../images/pic12.jpeg";
import pic13 from "../../images/pic13.jpeg";
import pic14 from "../../images/pic14.jpeg";
import pic15 from "../../images/pic15.jpeg";
import pic16 from "../../images/pic16.jpeg";
import pic17 from "../../images/pic17.jpeg";
import pic18 from "../../images/pic18.jpeg";
import pic19 from "../../images/pic19.jpeg";
import pic20 from "../../images/pic20.jpeg";
import pic21 from "../../images/pic21.jpeg";
import pic22 from "../../images/pic22.jpeg";
import pic23 from "../../images/pic23.jpeg";
import pic24 from "../../images/pic24.jpeg";
import pic25 from "../../images/pic25.jpeg";
import pic26 from "../../images/pic26.jpeg";
import pic27 from "../../images/pic27.jpeg";
import pic28 from "../../images/pic28.jpeg";

// 2. THE 5 HIGHLIGHT PHOTOS (For the main scrolling column)
const curatedPhotos = [
    pic11,
    pic10,
    pic1,
    pic26,
    pic20,
];

// 3. ALL 30 PHOTOS (For the full-screen gallery modal)
const allPhotos = [
    pic1, pic2, pic3, pic4, pic5, pic6, pic7, pic8, pic9, pic10,
    pic11, pic12, pic13, pic14, pic15, pic16, pic17, pic18, pic19, pic20,
    pic21, pic22, pic23, pic24, pic25, pic26, pic27, pic28, pic29, pic30
];

export default function ProjectStudy() {
    const [isGalleryOpen, setIsGalleryOpen] = useState(false);

    return (
        <>
            <section className="bg-brand-ink text-white py-24 md:py-32 relative">
                <div className="max-w-7xl mx-auto px-6 md:px-10">

                    {/* Top Header */}
                    <div className="mb-16 md:mb-24">
                        <div className="flex items-center gap-3 mb-6">
                            <span className="block w-10 h-px bg-brand-accent" />
                            <span className="text-xs tracking-[0.28em] uppercase text-white/55 font-medium">
                                Featured Case Study
                            </span>
                        </div>
                        <h2 className="font-display text-4xl md:text-5xl lg:text-6xl font-medium tracking-tighter">
                            The Sanford Redesign
                        </h2>
                    </div>

                    <div className="flex flex-col lg:flex-row gap-12 lg:gap-20 relative">

                        {/* Left Column: Sticky Context */}
                        <div className="lg:w-1/3 relative">
                            <div className="lg:sticky top-32">
                                <h3 className="text-2xl font-display font-medium text-white/90">
                                    Seamless integration. <br /> Flawless execution.
                                </h3>
                                <p className="mt-6 text-base leading-relaxed text-white/70">
                                    A complete structural gut and floor plan redesign. We removed load-bearing walls
                                    to achieve an open-concept flow, anchored by custom millimeter-tight millwork
                                    and a continuous-vein stone island. Handled with high-rise scheduling discipline
                                    from demo to final inspection.
                                </p>

                                <div className="mt-10 border-t border-white/10 pt-8 grid grid-cols-2 gap-y-6 gap-x-4">
                                    <div>
                                        <div className="text-xs uppercase tracking-[0.2em] text-white/45 mb-1.5">Scope</div>
                                        <div className="text-sm font-medium text-white/90">Full Interior Gut</div>
                                    </div>
                                    <div>
                                        <div className="text-xs uppercase tracking-[0.2em] text-white/45 mb-1.5">Timeline</div>
                                        <div className="text-sm font-medium text-white/90">14 Weeks</div>
                                    </div>
                                    <div>
                                        <div className="text-xs uppercase tracking-[0.2em] text-white/45 mb-1.5">Location</div>
                                        <div className="text-sm font-medium text-white/90">Springwater, ON</div>
                                    </div>
                                </div>

                                {/* TRIGGER BUTTON: Opens the modal */}
                                <button
                                    onClick={() => setIsGalleryOpen(true)}
                                    className="mt-12 group inline-flex items-center gap-3 text-sm font-bold tracking-[0.2em] uppercase text-brand-accent hover:text-white transition-colors"
                                >
                                    View Full Gallery ({allPhotos.length})
                                    <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform" />
                                </button>
                            </div>
                        </div>

                        {/* Right Column: The Main Image Scroll (Only shows the curated 5) */}
                        <div className="lg:w-2/3 flex flex-col gap-6 md:gap-10">
                            {curatedPhotos.map((imgSrc, index) => (
                                <div
                                    key={index}
                                    className="relative w-full overflow-hidden bg-brand-charcoal aspect-[4/3] md:aspect-[3/2]"
                                >
                                    <img
                                        src={imgSrc}
                                        alt={`Sanford Project Highlight ${index + 1}`}
                                        className="w-full h-full object-cover"
                                        loading="lazy"
                                    />
                                </div>
                            ))}
                        </div>

                    </div>
                </div>
            </section>

            {/* FULL SCREEN GALLERY MODAL (Shows all 30) */}
            {isGalleryOpen && (
                <div className="fixed inset-0 z-[100] bg-brand-ink/95 backdrop-blur-xl overflow-y-auto">

                    {/* Close Button */}
                    <button
                        onClick={() => setIsGalleryOpen(false)}
                        className="fixed top-6 right-6 md:top-10 md:right-10 p-2 text-white/70 hover:text-white hover:bg-white/10 rounded-full transition-colors z-[110]"
                        aria-label="Close gallery"
                    >
                        <X size={32} strokeWidth={1.5} />
                    </button>

                    {/* Modal Content */}
                    <div className="max-w-7xl mx-auto px-6 py-20 md:py-32">
                        <div className="mb-12">
                            <h2 className="font-display text-3xl md:text-4xl text-white">The Sanford Redesign</h2>
                            <p className="text-white/55 mt-2 tracking-widest uppercase text-sm">Full Project Gallery</p>
                        </div>

                        {/* CSS Columns create a perfect Pinterest-style masonry grid */}
                        <div className="columns-1 md:columns-2 lg:columns-3 gap-6 space-y-6">
                            {allPhotos.map((imgSrc, index) => (
                                <div key={index} className="break-inside-avoid">
                                    <img
                                        src={imgSrc}
                                        alt={`Sanford Full Gallery ${index + 1}`}
                                        className="w-full h-auto object-cover bg-brand-charcoal"
                                        loading="lazy"
                                    />
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            )}
        </>
    );
}
